SELECT DISTINCT t.team_name
FROM teams t
JOIN matches m ON t.team_id = m.team1_id OR t.team_id = m.team2_id;

SELECT matches.match_id, players.player_name
FROM matches
JOIN players ON matches.player_of_match_id = players.player_id;

SELECT match_id, COUNT(*) AS version_count 
FROM match_versions 
GROUP BY match_id;

SELECT mv.match_id 
FROM match_versions mv
WHERE mv.version_number > (
    SELECT AVG(version_number) 
    FROM match_versions
);

SELECT AVG(balls_faced) 
FROM player_statistics 
WHERE match_id = 1;
